processing.text:

if @@admin = 0 and @type = '1' begin
  if @@sysDatabaseName.dbo.MaxvOnline$System$GetAuthorize(@@admin, @@userID, 'Item', 'Edit') = 0 select @type = '0'
end

declare @message nvarchar(4000), @q nvarchar(4000), @fields nvarchar(4000), @duplicate nvarchar(4000), @irregular nvarchar(4000), @field varchar(32), @irregularChars varchar(128), @r int

select @irregularChars = &IrregularValue;
select @duplicate = case @@language when 'v' then N'Giá trị tại ô <span class="Highlight">%invalidCell</span> đã có hoặc lồng nhau.' else 'The value of cell <span class="Highlight">%invalidCell</span> is invalid or already exists.' end
select @irregular = case @@language when 'v' then N'Giá trị tại ô <span class="Highlight">%invalidCell</span> có chứa các ký tự: ' + @irregularChars else 'The value of cell <span class="Highlight">%invalidCell</span> contains any of the following characters: ' + @irregularChars  end

select @fields = 'ma_vt, ten_vt, ten_vt2, dvt, nhieu_dvt, vt_ton_kho, lo_yn, kk_yn, gia_ton, loai_vt, nh_vt1, nh_vt2, nh_vt3, ma_kho, ma_vi_tri, ma_thue, ma_thue_nk, tk_vt, sua_tk_vt,
  tk_gv, tk_dt,tk_dtnb, tk_tl, tk_dl, tk_spdd, tk_cl_vt, tk_ck, tk_cpbh, kieu_lo, cach_xuat, so_ngay_sp, so_ngay_bh, tao_lo, sl_min, sl_max, volume, weight'

-- Check
alter table @@table alter column ma_vt char(32)
create index i on @@table (ma_vt)

if @type = '0' delete @@table where ma_vt in (select ma_vt from dmvt)

select @field = 'ma_vt', @r = min(stt) from @@table where ma_vt like '%[' + @irregularChars + ']%'&Irregular;

select @field = 'dvt', @r = min(stt) from @@table where dvt not in (select dvt from dmdvt)&Error;
select @field = 'gia_ton', @r = min(stt) from @@table where gia_ton not in (1, 2, 3, 4)&Error;
select @field = 'loai_vt', @r = min(stt) from @@table where loai_vt not in (select ma_loai_vt from dmloaivt)&Error;

select @field = 'nh_vt1', @r = min(stt) from @@table where nh_vt1 <> '' and nh_vt1 not in (select ma_nh from dmnhvt where loai_nh = 1)&Error;
select @field = 'nh_vt2', @r = min(stt) from @@table where nh_vt2 <> '' and nh_vt2 not in (select ma_nh from dmnhvt where loai_nh = 2)&Error;
select @field = 'nh_vt3', @r = min(stt) from @@table where nh_vt3 <> '' and nh_vt3 not in (select ma_nh from dmnhvt where loai_nh = 3)&Error;

select @field = 'ma_kho', @r = min(stt) from @@table where ma_kho <> '' and ma_kho not in (select ma_kho from dmkho)&Error;
select @field = 'ma_vi_tri', @r = min(stt) from @@table where ma_vi_tri <> '' and ma_vi_tri not in (select a.ma_vi_tri from dmvitri a join @@table b on a.ma_kho = b.ma_kho)&Error;
select @field = 'ma_thue', @r = min(stt) from @@table where ma_thue <> '' and ma_thue not in (select ma_thue from dmthue)&Error;
select @field = 'ma_thue_nk', @r = min(stt) from @@table where ma_thue_nk <> '' and ma_thue_nk not in (select ma_thue from dmthuenk)&Error;

select @field = 'tk_vt', @r = min(stt) from @@table where tk_vt not in (select tk from dmtk where loai_tk = 1)&Error;
select @field = 'tk_gv', @r = min(stt) from @@table where tk_gv <> '' and tk_gv not in (select tk from dmtk)&Error;
select @field = 'tk_dt', @r = min(stt) from @@table where tk_dt <> '' and tk_dt not in (select tk from dmtk)&Error;
select @field = 'tk_dtnb', @r = min(stt) from @@table where tk_dtnb <> '' and tk_dtnb not in (select tk from dmtk)&Error;
select @field = 'tk_tl', @r = min(stt) from @@table where tk_tl <> '' and tk_tl not in (select tk from dmtk)&Error;
select @field = 'tk_dl', @r = min(stt) from @@table where tk_dl <> '' and tk_dl not in (select tk from dmtk where loai_tk = 1)&Error;
select @field = 'tk_spdd', @r = min(stt) from @@table where tk_spdd <> '' and tk_spdd not in (select tk from dmtk where loai_tk = 1)&Error;
select @field = 'tk_cl_vt', @r = min(stt) from @@table where tk_cl_vt <> '' and tk_cl_vt not in (select tk from dmtk where loai_tk = 1)&Error;
select @field = 'tk_ck', @r = min(stt) from @@table where tk_ck <> '' and tk_ck not in (select tk from dmtk where loai_tk = 1)&Error;
select @field = 'tk_cpbh', @r = min(stt) from @@table where tk_cpbh <> '' and tk_cpbh not in (select tk from dmtk where loai_tk = 1)&Error;

select @field = 'kieu_lo', @r = min(stt) from @@table where kieu_lo not in (1, 2)&Error;
select @field = 'cach_xuat', @r = min(stt) from @@table where cach_xuat not in (1, 2, 3, 4)&Error;
select @field = 'tao_lo', @r = min(stt) from @@table where (lo_yn = 0 and tao_lo = 1)&Error;

select a.*, cast(0 as bit) as ps into #k from @@table a join dmvt b on a.ma_vt = b.ma_vt
delete @@table where ma_vt in (select ma_vt from #k)

-- 
select @field = 'ma_vt'
select @q = 'select top 1 @r = a.stt from @@table a, @@table b with (index(i)) where a.ma_vt <> b.ma_vt and a.ma_vt =rtrim(b.ma_vt) '
exec sp_executesql @q, N'@r int output', @r = @r output&Duplicate;
select top 1 @r = a.stt from @@table a, dmvt b with (index(PK_dmvt)) where a.ma_vt = rtrim(b.ma_vt)&Duplicate;
select @q = 'select top 1 @r = b.stt from dmvt a, @@table b with (index(i)) where a.ma_vt = rtrim(b.ma_vt)'
exec sp_executesql @q, N'@r int output', @r = @r output&Duplicate;

-- Insert
select @q = 'insert into dmvt(' + @fields + ', status, datetime0, datetime2, user_id0, user_id2, ma_vt2, ong_ba, ghi_chu, '
select @q = @q + 'ma_td1, ma_td2, ma_td3, sl_td1, sl_td2, sl_td3, gc_td1, gc_td2, gc_td3, s1, s2, s3, s4, s5, s6)'
select @q = @q + 'select ' + @fields + ', ''1'', getdate(), getdate(), rtrim(@@userID), rtrim(@@userID), '''', '''', '''', '
select @q = @q + ''''', '''', '''', 0, 0, 0, '''', '''', '''', '''', '''', '''', 0, 0, 0 from @@table'
exec sp_executesql @q

insert into dmqddvt(ma_vt, dvt, he_so, xtype, status, datetime0, datetime2, user_id0, user_id2)
  select ma_vt, dvt, 1, 'S', '1', getdate(), getdate(), @@userID, @@userID from @@table where nhieu_dvt = 1

if @type = 1 begin
  create index i on #k (ma_vt)
  select distinct ma_vt into #ct70 from ct70 where ma_vt in (select ma_vt from #k)
  select distinct ma_vt into #ct90 from ct90 where ma_vt in (select ma_vt from #k)
  create index i on #ct70 (ma_vt)
  create index i on #ct90 (ma_vt)

  update #k set ps = 1 from #k a join #ct70 b on a.ma_vt = b.ma_vt
  update #k set ps = 1 from #k a join #ct90 b on a.ma_vt = b.ma_vt

  delete dmqddvt from dmqddvt a join #k b on a.ma_vt = b.ma_vt where a.xtype = 'S' and b.ps = 0 and b.nhieu_dvt = 0
  update dmqddvt set dvt = b.dvt from dmqddvt a join #k b on a.ma_vt = b.ma_vt where a.xtype = 'S' and b.ps = 0

  update dmvt set ten_vt = b.ten_vt, ten_vt2 = b.ten_vt2, dvt = case when b.ps = 0 then b.dvt else a.dvt end, nhieu_dvt = case when b.ps = 0 then b.nhieu_dvt else a.nhieu_dvt end, 
      vt_ton_kho = b.vt_ton_kho, lo_yn = b.lo_yn, kk_yn = b.kk_yn, gia_ton = b.gia_ton, loai_vt = b.loai_vt, nh_vt1 = b.nh_vt1,
      nh_vt2 = b.nh_vt2, nh_vt3 = b.nh_vt3, ma_kho = b.ma_kho, ma_vi_tri = b.ma_vi_tri, ma_thue = b.ma_thue, ma_thue_nk = b.ma_thue_nk, tk_vt = b.tk_vt, sua_tk_vt = b.sua_tk_vt, tk_gv = b.tk_gv,
      tk_dt = b.tk_dt, tk_dtnb = b.tk_dtnb, tk_tl = b.tk_tl, tk_dl = b.tk_dl, tk_spdd = b.tk_spdd, tk_cl_vt = b.tk_cl_vt, tk_ck = b.tk_ck, tk_cpbh = b.tk_cpbh, kieu_lo = b.kieu_lo, cach_xuat = b.cach_xuat, so_ngay_sp = b.so_ngay_sp, 
      so_ngay_bh = b.so_ngay_bh, tao_lo = b.tao_lo, sl_min = b.sl_min, sl_max = b.sl_max, volume = b.volume, weight = b.weight, datetime2 = getdate(), user_id2 = @@userID
    from dmvt a join #k b on a.ma_vt = b.ma_vt
end
